-- =====================================================
-- Pedagogy Library — generated by seed/build_pedagogy.mjs
-- 240 entries (60 indicators × 4 levels)
-- =====================================================

INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (1, 4, 'The teacher demonstrates expert-level command of content AND keeps current with research on how children develop and learn. Content choices are deliberate, accurate, and connected to how the brain forms schema in this subject.', '["Uses precise academic vocabulary fluently and defines it for students","Makes cross-disciplinary connections without being asked","Corrects misconceptions on the fly with correct disciplinary reasoning","References current research or recent professional reading in planning"]', '["Share your content expertise by co-planning with a less experienced teammate","Present a 10-minute content deep-dive at your next PLC meeting","Keep a \"misconception log\" of the content questions students ask — feed it into next year''s unit plans"]', '["Pair this teacher as a content anchor on the grade-level team","Invite them to model-teach a unit opening while peers observe"]', '[{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"},{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"},{"title":"Enhancing Professional Practice: A Framework for Teaching","source":"Charlotte Danielson (ASCD, 2nd ed.)","type":"book"}]', 'Your practice in knowledge reflects mastery-level work that should be named, preserved, and shared with colleagues. Keep doing the intellectual work of staying current — your students are getting the benefit of a scholar in front of them.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (1, 3, 'Content and developmental knowledge are solid and reliable. Students get accurate instruction and the teacher can flex when a student asks an unexpected question.', '["Explanations are accurate and age-appropriate","Minor misconceptions are caught and corrected","Shows awareness of how students this age typically reason about the content"]', '["Pick one unit this semester and read one recent article on how children learn that specific topic","Build a \"key misconceptions\" section into each unit plan","Map content to the North Dakota content standards at the sub-standard level"]', '["Rethinking Teacher Supervision and Evaluation","North Dakota Content Standards"]', '[{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"},{"title":"North Dakota Content Standards","source":"www.nd.gov/dpi","type":"state-standard"}]', 'Your knowledge is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Your content base is reliable; the next growth move is from confident to scholarly by layering in research on how students develop in this specific subject.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (1, 2, 'The teacher can get through the content as it is scripted, but gaps show when students push past the surface or when the curriculum asks for disciplinary reasoning.', '["Relies heavily on textbook phrasing","Hesitates or deflects when students ask \"why\"","Occasional factual inaccuracies that go uncorrected"]', '["Pre-read the next three units and identify the five concepts you least understand — study those first","Partner with a content-strong colleague for weekly 20-minute content reviews","Use a content self-assessment against state standards and flag your growth areas"]', '["Set up a weekly 20-minute content study block with a strong peer","Observe a strong content model in another classroom for the next unit"]', '[{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"},{"title":"North Dakota Content Standards","source":"www.nd.gov/dpi","type":"state-standard"}]', 'Your knowledge shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Closing this gap is not about effort — it is about study time. Let''s protect weekly content-study time on your calendar and re-check at the next observation.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (1, 1, 'Content knowledge gaps are broad enough that students are receiving inaccurate or incoherent instruction. This is a classroom-integrity issue that requires an immediate plan.', '["Multiple content errors per observation","Cannot answer foundational student questions in the subject","Curriculum sequencing reflects misunderstanding of the discipline"]', '["Work with the principal to identify a content mentor this week","Begin daily content study for 30 minutes before unit delivery","Submit weekly content-preparation plans for appraiser review"]', '["Assign a dedicated content mentor","Build a 30/60/90-day content-competency improvement plan with weekly check-ins"]', '[{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"},{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"}]', 'I want to be direct and supportive at the same time: your knowledge is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We will build a short, specific content-study plan together this week and I will check in with you daily for the first two weeks.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (2, 4, 'The year is architected against standards and external assessments — not assembled lesson-by-lesson. Every unit can be traced back to specific standards and the summative assessments students will eventually face.', '["Year-at-a-glance document posted or shared with coach/appraiser","Unit plans explicitly cite the ND standards they address","Curriculum maps show vertical alignment to prior and next grade"]', '["Share your year-at-a-glance with the team as a model","Audit once per semester for standards gaps or over-coverage"]', '["Invite this teacher to help lead next year''s curriculum mapping work."]', '[{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"},{"title":"North Dakota Content Standards","source":"www.nd.gov/dpi","type":"state-standard"}]', 'Your practice in standards reflects mastery-level work that should be named, preserved, and shared with colleagues. Your backward-planned year is a model of what the Marshall rubric means by "tightly aligned to high standards."');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (2, 3, 'Standards alignment is real. The year is planned against standards, and students will be prepared for external assessments at a level that meets expectations.', '["Unit plans reference standards","Pacing guide is followed","Assessments match standards at reasonable rigor"]', '["Move from \"standard referenced\" to \"standard anchored\" by adding an essential question and a measurable performance goal to each unit","Build a simple end-of-year backward map from the state assessment back to Week 1"]', '["Co-plan one unit using a UbD backward-design template."]', '[{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"},{"title":"North Dakota Content Standards","source":"www.nd.gov/dpi","type":"state-standard"}]', 'Your standards is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Your alignment work is where it should be; the highest-leverage next move is to go from ''referenced'' to backward-designed from the end-of-year assessment.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (2, 2, 'Some thinking has happened about standards and tests, but planning is still largely lesson-by-lesson rather than unit-by-unit or year-by-year.', '["Standards appear in some lesson plans but not all","No written pacing guide","Summative assessments appear without explicit standards mapping"]', '["This month: write a one-page pacing guide against the ND standards for the remainder of the year","Pick one upcoming unit and map every lesson objective to a specific sub-standard","Identify the three highest-leverage standards the state assessment will test and double-plan them"]', '["Co-build a one-page pacing guide in the next coaching session."]', '[{"title":"North Dakota Content Standards","source":"www.nd.gov/dpi","type":"state-standard"},{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"}]', 'Your standards shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. The fastest path to Effective here is a one-page pacing guide we can build together in about 45 minutes.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (2, 1, 'Planning is reactive. The teacher is unfamiliar with the standards their students will be tested on, which means students are at real risk of not being prepared.', '["No written pacing guide","Cannot identify which standards a lesson addresses","State-assessment rigor is unfamiliar"]', '["Meet with the principal this week to build an emergency pacing plan for the rest of the year","Review the ND standards document for your grade/subject before the next planning session"]', '["Require a written weekly plan with standards cited, reviewed by appraiser."]', '[{"title":"North Dakota Content Standards","source":"www.nd.gov/dpi","type":"state-standard"}]', 'I want to be direct and supportive at the same time: your standards is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We need to build you a pacing plan this week. I will block time on both of our calendars.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (3, 4, 'Units are designed, not just sequenced. They contain big ideas, essential questions, and a deliberate mix of Bloom''s levels from recall all the way to creation.', '["Essential questions posted","Units include explicit knowledge AND skill goals","Students can articulate the big idea of the unit mid-unit"]', '["Share a unit map with the team as a UbD model","Start a unit artifact library the school can reuse"]', '["Invite this teacher to lead a unit-design session with peers."]', '[{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"},{"title":"Bloom''s Revised Taxonomy","source":"Anderson & Krathwohl (2001)","type":"framework"}]', 'Your practice in units reflects mastery-level work that should be named, preserved, and shared with colleagues. Your unit architecture models what Wiggins & McTighe call "backward design."');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (3, 3, 'Most units have the elements of good design — big ideas, essential questions, mix of Bloom''s — but not always consistently.', '["Most units have essential questions","Higher-order thinking shows up but is uneven across units"]', '["Use a one-page unit template for every unit this semester","Aim for at least 30% of lesson activities at Bloom''s Analyze level or higher"]', '["Co-design one under-developed unit using UbD."]', '[{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"},{"title":"Bloom''s Revised Taxonomy","source":"Anderson & Krathwohl (2001)","type":"framework"}]', 'Your units is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Pick the weakest unit on your calendar and rebuild it backward from a performance task — that single redesign will move you toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (3, 2, 'Planning is happening mostly at the lesson level. Larger structure and higher-order thinking are thought about, but not intentionally designed into the work students do.', '["Lesson plans exist but no unit-level planning document","Activities skew toward Remember/Understand on Bloom''s"]', '["Adopt a one-page unit plan template starting with the next unit","Audit the next week of lessons against Bloom''s — add at least two Analyze/Evaluate tasks"]', '["Co-plan the next unit together end-to-end."]', '[{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"},{"title":"Bloom''s Revised Taxonomy","source":"Anderson & Krathwohl (2001)","type":"framework"}]', 'Your units shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Moving your planning lens from ''lesson'' to ''unit'' is the unlock here. Let''s co-plan the next unit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (3, 1, 'Teaching is ad hoc day-to-day. There is no discernible larger structure and students cannot articulate what they are supposed to be learning over time.', '["No unit plan exists","Lessons do not build on each other","Students cannot describe the arc of the unit"]', '["This week: build one unit plan with essential question, knowledge goals, and skill goals"]', '["Provide a unit template and co-author two units over the next three weeks."]', '[{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"}]', 'I want to be direct and supportive at the same time: your units is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We are going to build unit plans together — starting this week — because students need a coherent through-line.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (4, 4, 'A full assessment system is planned: diagnostic, on-the-spot (formative), interim, and summative. Assessment decisions are designed before instruction, not after.', '["Diagnostic at unit start","Frequent formative checks","Interim assessments every 4-6 weeks","Summatives aligned to standards and rubrics"]', '["Share your assessment system with the team","Run one data meeting around an interim assessment"]', '["Invite to lead a data-team session."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"},{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"}]', 'Your practice in assessments reflects mastery-level work that should be named, preserved, and shared with colleagues. Your planned assessment system is exactly what Wiliam calls "assessment for learning."');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (4, 3, 'The teacher plans formative checks and unit assessments. Some, but not all, of the pieces of a full system are present.', '["Formative checks show up in lessons","Unit tests exist and are planned in advance"]', '["Add a diagnostic to at least two units this semester","Introduce one mid-unit interim check"]', '["Co-design a diagnostic and an interim for the next unit."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your assessments is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Add a diagnostic and an interim to the units you already have — that''s the move toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (4, 2, 'Unit tests are being drafted as the unit unfolds rather than designed before instruction begins. Assessment is an afterthought rather than a design driver.', '["Tests are created late in the unit","Formative checks are rare or informal","Rubrics are not shared with students"]', '["Write the summative BEFORE teaching the next unit","Add 3-5 formative checks per week","Share the rubric with students on day 1"]', '["Co-write the summative for the next unit together before teaching begins."]', '[{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"},{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your assessments shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Writing the summative before the unit starts reverses the design and will sharpen every lesson in between.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (4, 1, 'Final tests are written just before they are given. This means instruction cannot be aligned to what is being measured, and student learning is not being monitored.', '["Tests appear the week they are given","No formative checks","No rubrics"]', '["Stop this practice this week — every new unit must begin with a written summative"]', '["Require summatives to be submitted to appraiser before the unit begins."]', '[{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"}]', 'I want to be direct and supportive at the same time: your assessments is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. This pattern must change starting with the next unit; I will help you design the summative.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (5, 4, 'The teacher has deeply studied how students get confused with this content and has multiple pre-planned strategies to address each likely misconception.', '["Unit plans include a misconceptions section","Teacher cites specific student confusions in advance","Teacher has \"if/then\" contingencies for the top 3-5 likely misconceptions"]', '["Add a \"top misconceptions\" companion to each unit plan as a PD contribution"]', '["Let this teacher lead a \"student thinking\" PD session."]', '[{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"},{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your practice in anticipation reflects mastery-level work that should be named, preserved, and shared with colleagues. Your anticipation of student thinking is the hallmark of a master teacher — keep recording these patterns.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (5, 3, 'The teacher anticipates common misconceptions and plans to address them. This is the essential teacher mindset that makes instruction responsive.', '["Misconceptions named in planning conversations","Teacher can tell you what students will get wrong and why"]', '["Write the top 2 misconceptions into each lesson plan","Collect student thinking samples over the unit to refine your anticipation bank"]', '["Do a \"cognitive task analysis\" of one tricky lesson together."]', '[{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"},{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your anticipation is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Pushing from 1-2 anticipated misconceptions per unit to 3-5 with specific plans will move this to Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (5, 2, 'There is a loose hunch about where students might struggle, but not a planned strategy to surface or repair the misconception.', '["Teacher can name \"something might be hard\" but not a specific student-thinking error","No repair plan"]', '["Before each upcoming lesson, write one sentence: \"Where will students probably get this wrong, and what will I do?\"","Ask students what confused them — document patterns"]', '["Use a student-thinking protocol on student work samples in the next coaching cycle."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your anticipation shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. One sentence per lesson — "where will students trip, and what will I do?" — closes most of this gap in a few weeks.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (5, 1, 'Instruction is delivered as if students will all understand the first time. When students struggle, the teacher is surprised and has no repair plan.', '["No misconceptions planning","Teacher blames students for confusion","No repair strategies"]', '["Begin adding a \"confusion check\" to every lesson plan starting next week"]', '["Co-plan three lessons and insist on a written misconception section for each."]', '[{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"},{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'I want to be direct and supportive at the same time: your anticipation is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. The frame to internalize: student confusion is information, not failure. We will work this together lesson-by-lesson.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (6, 4, 'Every lesson has a clear, measurable objective tightly anchored to standards AND to the larger unit. Students always know what they are learning, why, and how it fits.', '["Objective is posted in student-friendly language","Objective is measurable (students can do X by end of lesson)","Students can restate the objective mid-lesson"]', '["Share your lesson template with the team","Add a \"how this lesson fits the unit\" line to your template if not already there"]', '["Use this teacher as a model in a lesson-design workshop."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"},{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your practice in lessons reflects mastery-level work that should be named, preserved, and shared with colleagues. Your lesson design models what Marzano calls "clear learning goals" — students always know where they are going.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (6, 3, 'Lessons are built around measurable outcomes aligned with unit goals. Students have a clear sense of what they are learning.', '["Objectives are stated and measurable","Lessons connect to unit outcomes"]', '["Tighten objectives to SWBAT + measurable verb + condition format","Open each lesson with a 30-second \"why this matters\" hook"]', '["Co-write 3 lesson objectives together using a precise verb bank."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"},{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your lessons is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Sharpen your objective language — measurable verbs and conditions — and this jumps to Highly Effective quickly.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (6, 2, 'There is thought behind each lesson but the connection to long-term goals is loose. Objectives exist but are general.', '["Objectives are broad (\"Students will learn about fractions\")","Lessons do not clearly accumulate toward a unit goal"]', '["Rewrite objectives using SWBAT + Bloom''s verb + measurable condition","End each lesson with a check-for-objective mastery"]', '["Co-plan three consecutive lessons and check each against the unit destination."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"},{"title":"Bloom''s Revised Taxonomy","source":"Anderson & Krathwohl (2001)","type":"framework"}]', 'Your lessons shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Tightening your objective writing and the end-of-lesson mastery check is the move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (6, 1, 'Lessons are aimed at filling time rather than advancing specific learning. Students are being entertained or simply moved through a textbook.', '["No objective or vague (\"today we''re doing chapter 5\")","No closure or mastery check","Activities with no obvious learning purpose"]', '["Every lesson plan must begin with a written SWBAT starting this week"]', '["Require lesson plans with SWBAT written in advance, submitted daily for two weeks."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"},{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'I want to be direct and supportive at the same time: your lessons is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We are going to require a written SWBAT for every lesson for the next two weeks — this is the base habit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (7, 4, 'Lessons are designed so that most or all students are motivated AND actively learning. Engagement is planned, not hoped for.', '["Lessons include a hook tied to student lives","Active learning tasks in every segment","Planned checks for all-student involvement"]', '["Share your engagement planning strategies with the team"]', '["Co-present an engagement PD with the coach."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your practice in engagement (planning) reflects mastery-level work that should be named, preserved, and shared with colleagues. You plan engagement the way Lemov describes it — as architecture, not accident.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (7, 3, 'Lessons are designed to be relevant and likely to engage most students.', '["Relevance hooks are present","Most students appear on-task in designed tasks"]', '["Layer in a planned turn-and-talk or cold-call sequence every 7-10 minutes","Plan for the 20% you lose most often and build an engagement move for them"]', '["Use an engagement heatmap in the next observation."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your engagement (planning) is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Lifting this to Highly Effective is about designing for the hardest-to-reach students in the room — not the middle.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (7, 2, 'Lessons might spark some student interest, but engagement isn''t the design driver. A few students will engage; many will coast.', '["Occasional relevance hooks","Most lesson time is passive"]', '["Redesign the next three lessons to include at least 4 active participation moves (turn-and-talk, cold call, choral response, written response)","Start every lesson with a 60-second \"hook\""]', '["Use TLAC engagement techniques as a coaching focus."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your engagement (planning) shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Designed active participation moves every 7-10 minutes is the upgrade — let''s pick three to practice.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (7, 1, 'Lessons are unlikely to motivate or involve most students. The design assumes students will engage themselves.', '["Long stretches of teacher talk","Passive tasks","Student disengagement visible throughout"]', '["Add a planned active participation move every 5 minutes to every lesson starting this week"]', '["Three-week engagement coaching cycle using TLAC techniques."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'I want to be direct and supportive at the same time: your engagement (planning) is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Engagement has to be designed into the lesson, not hoped for — let''s coach specific techniques this month.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (8, 4, 'Materials are deliberately chosen for quality, representation, and fit with learning goals. Technology is used when it adds real value.', '["Multicultural perspectives evident","Primary sources where appropriate","Technology augments, doesn''t replace","Materials vetted for reading level and accuracy"]', '["Share your materials vetting criteria with the team"]', '["Lead a materials-curation PD."]', '[{"title":"ASCD ''Educational Leadership'' archives","source":"ASCD","type":"journal"},{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"}]', 'Your practice in materials reflects mastery-level work that should be named, preserved, and shared with colleagues. Your material selection reflects a curator''s eye — keep auditing for representation and quality each year.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (8, 3, 'Materials are appropriate, diverse, and support learning. Technology is used reasonably.', '["Mixed media","Some multicultural materials","Technology used functionally"]', '["Audit one unit''s materials for multicultural representation","Replace one worksheet per week with a primary source or authentic text"]', '["Use a materials-audit tool during the next planning session."]', '[{"title":"ASCD ''Educational Leadership'' archives","source":"ASCD","type":"journal"}]', 'Your materials is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. An annual materials audit for representation and rigor lifts this to Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (8, 2, 'Materials are a mix of quality and convenience. Some strong resources alongside workbook pages and generic worksheets.', '["Over-reliance on textbook or workbook","Worksheets dominate","Few multicultural materials"]', '["Swap one worksheet per lesson for a richer task (primary source, short text, problem-based task)","Build a unit-level materials list during planning"]', '["Co-curate resources for the next unit."]', '[{"title":"ASCD ''Educational Leadership'' archives","source":"ASCD","type":"journal"}]', 'Your materials shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Small swaps — one worksheet at a time — accumulate quickly into stronger materials.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (8, 1, 'Instruction is built almost entirely on mediocre textbooks, workbooks, or worksheets. Students are doing low-rigor tasks most of the time.', '["Worksheet-dominated lessons","No primary sources","No technology integration that enhances learning"]', '["Replace at least one worksheet per lesson with a richer task starting this week"]', '["Co-curate materials for the next full unit."]', '[{"title":"ASCD ''Educational Leadership'' archives","source":"ASCD","type":"journal"},{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"}]', 'I want to be direct and supportive at the same time: your materials is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. The worksheet-driven pattern has to end — we will rebuild materials unit by unit starting now.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (9, 4, 'Every lesson is designed with differentiation built in — complex tasks are broken down, and multiple entry points address different learning needs, styles, and interests.', '["Tiered tasks or flexible grouping planned in advance","Scaffolds are named in the lesson plan","Enrichment options for fast finishers are intentional"]', '["Share your differentiation planning template with the team"]', '["Lead a differentiation design PD."]', '[{"title":"Enhancing Professional Practice: A Framework for Teaching","source":"Charlotte Danielson (ASCD, 2nd ed.)","type":"book"},{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your practice in differentiation (planning) reflects mastery-level work that should be named, preserved, and shared with colleagues. Planned differentiation for all learners is what the Marshall rubric calls "Highly Effective" — keep naming scaffolds explicitly.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (9, 3, 'Differentiation targets several learning needs and interests. Not every student gets a perfectly customized path, but most do.', '["2-3 differentiation moves planned per lesson","Tiered questioning","Student choice in some tasks"]', '["Add a specific scaffold for your lowest-readiness learner in every lesson plan","Add an enrichment option for your highest-readiness learner"]', '["Use a differentiation audit tool in the next coaching cycle."]', '[{"title":"Enhancing Professional Practice: A Framework for Teaching","source":"Charlotte Danielson (ASCD, 2nd ed.)","type":"book"}]', 'Your differentiation (planning) is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Name your differentiation moves in writing on the plan — the discipline of writing them catalyzes more of them.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (9, 2, 'Differentiation happens reactively for special-needs students but isn''t designed into the lesson for all learners.', '["IEP accommodations show up but nothing else","One-size-fits-all tasks for the rest of the class"]', '["For the next three lessons, plan one scaffold and one enrichment task","Review student data before planning to target specific learners"]', '["Use student readiness data to co-plan differentiated tasks."]', '[{"title":"Enhancing Professional Practice: A Framework for Teaching","source":"Charlotte Danielson (ASCD, 2nd ed.)","type":"book"}]', 'Your differentiation (planning) shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Moving differentiation from IEP-only to designed-for-all is the next step.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (9, 1, 'Lessons are designed for a mythical "average" student. Students who need more support fall behind; students who need more challenge coast.', '["Identical tasks for all students","No scaffolds or extensions","No use of student data in planning"]', '["Begin adding one scaffold and one extension to every lesson plan this week"]', '["Three-week coaching cycle on planned differentiation using student data."]', '[{"title":"Enhancing Professional Practice: A Framework for Teaching","source":"Charlotte Danielson (ASCD, 2nd ed.)","type":"book"},{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'I want to be direct and supportive at the same time: your differentiation (planning) is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. One scaffold, one extension, every lesson — starting this week. That''s the base habit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (10, 4, 'The physical classroom is an instructional tool. Arrangement, materials, and displays are all designed to maximize learning.', '["Furniture supports collaborative and individual work","Anchor charts are student-generated and current","Student work is prominently displayed with rubrics/commentary","Materials are easily accessible to students"]', '["Take photos of your room setup and share with the team"]', '["Use this room as a model during new-teacher induction."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"},{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your practice in environment reflects mastery-level work that should be named, preserved, and shared with colleagues. Your classroom is an instructional tool in itself — keep refreshing anchor charts so they stay a thinking resource.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (10, 3, 'Furniture, materials, and displays support the unit and lesson goals.', '["Current anchor charts posted","Flexible seating for different activities","Some student work displayed"]', '["Replace any display older than 30 days","Involve students in creating anchor charts"]', '["Do a classroom environment audit together."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your environment is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Keep anchor charts fresh and student-generated and this moves toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (10, 2, 'The classroom is functional for the lesson but doesn''t do instructional work on its own. Displays are mostly decorative.', '["Static, older displays","Decorative rather than instructional posters","Materials access requires teacher intermediary"]', '["Replace decorative displays with unit-aligned anchor charts","Build a \"materials center\" students can access independently"]', '["Co-design a classroom refresh tied to the next unit."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your environment shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Your walls can teach — let''s redesign them around your current unit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (10, 1, 'The room reflects neither current learning nor student work. Arrangement is conventional and disconnected from instruction.', '["Rows of desks unchanging","Blank or irrelevant walls","No student work displayed"]', '["Refresh at least three wall displays this week with current unit content"]', '["Schedule a classroom environment redesign session with the coach."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'I want to be direct and supportive at the same time: your environment is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. The environment piece is actually the quickest to move — a single afternoon can make a real difference.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (11, 4, 'Behavior expectations are communicated and enforced with such clarity, consistency, and tenacity that they feel like the room''s default setting.', '["Expectations posted and taught, not just posted","Teacher responds to every violation — no missed calls","Expectations named in student language"]', '["Share your expectations-teaching plan with the team"]', '["Model expectation-teaching for new teachers."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your practice in expectations reflects mastery-level work that should be named, preserved, and shared with colleagues. Your expectations work is what Lemov calls "100 percent" — preserve that consistency all year.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (11, 3, 'Expectations are clear, consistent, and generally enforced.', '["Posted expectations referenced in class","Most violations addressed","Tone is calm and professional"]', '["Close the \"miss rate\" — commit to addressing 100% of expectation gaps","Teach expectations explicitly three times in the first two weeks of any new quarter"]', '["Use a tally tool to measure consistency."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your expectations is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Moving from 90% to 100% consistency is the move toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (11, 2, 'Rules exist on the wall but aren''t actively taught or consistently enforced. Students know the rules in theory but not in practice.', '["Rules posted but not explicitly taught","Inconsistent enforcement","Selective response to the same behavior"]', '["Explicitly re-teach expectations next Monday","Pre-commit to a specific response for the top 3 misbehaviors","Track your consistency with a simple tally for a week"]', '["Observe and tally enforcement consistency; debrief weekly."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your expectations shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Consistency is the unlock — we can design a specific plan together.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (11, 1, 'Rules and consequences emerge ad hoc. Students have no clear sense of what is expected, and enforcement feels arbitrary.', '["No posted expectations or they''re ignored","Consequences vary wildly for the same behavior","Students argue the rules frequently"]', '["This week: co-create expectations with students and teach them explicitly"]', '["Immediate coaching cycle on expectation setting and consistency."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'I want to be direct and supportive at the same time: your expectations is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We need a reset on expectations — let''s do that together this week.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (12, 4, 'Students experience genuine warmth, care, respect, and fairness. Strong relationships are visible even in tough moments.', '["Teacher greets students by name at the door","Individual check-ins with struggling students","Teacher knows non-academic details about students","Tough conversations happen privately and restoratively"]', '["Mentor a teacher growing in relationship skills"]', '["Lead relationship-building PD."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"},{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your practice in relationships reflects mastery-level work that should be named, preserved, and shared with colleagues. The relational foundation you''ve built is what makes every other instructional move stick.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (12, 3, 'Fair and respectful treatment of students is the norm; positive relationships exist with most of the class.', '["Warm interactions","Fair corrections","No favorites visible"]', '["Build one individual relationship a week with a student you don''t know well","Greet every student at the door by name"]', '["Use a 2x10 relationship-building strategy with disengaged students."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your relationships is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Targeting the 2-3 students you know least well is the move toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (12, 2, 'Some students experience strong relationships; others experience distance, inconsistency, or unintentional favoritism.', '["Stronger rapport with some students","Occasional sharp tone with others","Unequal investment across the class"]', '["Use a 2x10 strategy (2 minutes of non-academic conversation for 10 consecutive days) with 3 students you know least","Audit your call-ratio — are you calling on the same few students?"]', '["2x10 coaching cycle with a focus list of students."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your relationships shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A 2x10 strategy with three specific students will shift this quickly.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (12, 1, 'Sarcasm, unfairness, or favoritism shows up. Students don''t trust the teacher to be consistent or caring.', '["Public criticism of students","Visible favorites","Sharp or dismissive tone"]', '["Begin a 2x10 strategy with your five most disconnected students this week","Remove sarcasm from teacher language"]', '["Intensive relationship-building coaching cycle."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'I want to be direct and supportive at the same time: your relationships is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. This is the highest-priority growth area — students cannot learn from someone they don''t trust.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (13, 4, 'Student respect is so established that disruption of learning feels unthinkable to the students themselves.', '["Students self-correct and peer-correct","Disruption is rare and quickly self-repaired","Visitors comment on the learning culture"]', '["Share your culture-building practices in PD"]', '["Feature this classroom for visitors and new teachers."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your practice in respect reflects mastery-level work that should be named, preserved, and shared with colleagues. The climate you have built is something colleagues should come see.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (13, 3, 'The teacher commands respect and refuses to allow disruption to eat learning time.', '["Prompt, calm responses to disruption","Clear authority without harshness","Disruption rare and short-lived"]', '["Shift from \"commanding\" respect to students \"owning\" the learning culture","Invite students into culture conversations"]', '["Co-lead a student-voice culture session."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your respect is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Moving from teacher-held respect to student-owned culture is the next step.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (13, 2, 'Some students respect the teacher and the learning; others don''t. Disruptions are regular and eat learning time.', '["Regular disruptions","Teacher escalates to get control","Same students disrupting repeatedly"]', '["Use stronger narration and non-verbal moves","Front-load expectations at start of each class for two weeks","Build relationships with chronic disruptors outside class"]', '["Lemov-focused coaching cycle on strong voice + what to do."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your respect shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. We need to close the disruption leak — specific TLAC moves will help.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (13, 1, 'The teacher is not respected. The classroom is frequently chaotic and sometimes unsafe.', '["Chaos is frequent","Teacher yells or gives up","Student safety concerns"]', '["Immediate intervention plan with admin support"]', '["Daily coaching support for 2-3 weeks; consider classroom-swap shadow of a strong peer."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'I want to be direct and supportive at the same time: your respect is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. This is an urgent safety and learning issue that needs immediate structured support.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (14, 4, 'The classroom runs a real social-emotional program. Students develop interaction skills, self-regulation, and empathy as intentionally as they develop academic skills.', '["Explicit SEL instruction","Morning meetings or circle time","Students use SEL vocabulary (feelings, strategies)","Peer mediation"]', '["Share your SEL structure with the team"]', '["Lead SEL PD."]', '[{"title":"CASEL SEL Framework and Competencies","source":"casel.org","type":"framework"},{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your practice in social-emotional reflects mastery-level work that should be named, preserved, and shared with colleagues. Your SEL work reflects what CASEL calls a systemic approach — not an add-on.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (14, 3, 'Positive interactions are the norm and useful social skills are taught when they come up.', '["Positive classroom tone","Conflict-resolution language used","Students help each other"]', '["Add explicit SEL mini-lessons once a week","Use morning meetings or circle structures"]', '["Introduce CASEL five competencies as a planning lens."]', '[{"title":"CASEL SEL Framework and Competencies","source":"casel.org","type":"framework"},{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your social-emotional is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. A weekly explicit SEL touch will move this to Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (14, 2, 'Behavior is addressed reactively. Students are lectured rather than taught skills; problem behavior is personalized rather than skill-identified.', '["Public lectures on behavior","Bad students narrative","No SEL instruction"]', '["Replace behavior lectures with skill teaching (\"We''re going to practice...\")","Start explicit SEL instruction"]', '["Teach the replacement-behavior lens."]', '[{"title":"CASEL SEL Framework and Competencies","source":"casel.org","type":"framework"}]', 'Your social-emotional shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Behavior is a skill — let''s teach it rather than lecture about it.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (14, 1, 'Students are publicly berated and blamed. This creates an unsafe climate and damages relationships.', '["Public shaming","Blame language","Unsafe emotional climate"]', '["Eliminate public shaming starting immediately","Conduct private, restorative conversations instead"]', '["Immediate coaching on restorative practices."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'I want to be direct and supportive at the same time: your social-emotional is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Public berating must stop immediately — we will replace it with private, restorative conversations.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (15, 4, 'Routines were established and practiced at the start of the year, and students maintain them without reminders all year long.', '["Entry, exit, transitions, materials all automatic","Students self-correct routine breaks","Instructional time is not lost to procedural friction"]', '["Share your routine scripts with the team","Re-teach routines after long breaks"]', '["Use as a model during new-teacher summer training."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your practice in routines reflects mastery-level work that should be named, preserved, and shared with colleagues. Your routine work is the invisible engine of your classroom — protect it.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (15, 3, 'Routines are taught and mostly maintained across the year, with periodic reinforcement.', '["Common routines run smoothly","Re-teaching happens after breaks"]', '["Script and practice one routine per week for two weeks","Time your transitions — aim for under 60 seconds"]', '["Routine audit with a video analysis."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your routines is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Tightening transitions to under 60 seconds is a clear lift toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (15, 2, 'Routines were taught but are already breaking down. The teacher is spending instructional time re-directing procedures.', '["Ragged transitions","Procedural disputes mid-lesson","Time lost to \"what do I do\" questions"]', '["Re-teach the top 3 most-broken routines next week","Script the routine with clear steps and practice it three times"]', '["Routine-by-routine coaching cycle."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your routines shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Routines are an investment that pays back all year — let''s re-teach next week.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (15, 1, 'Routines were never established. Every procedure is a negotiation and the teacher is constantly managing behavior rather than teaching.', '["No predictable routines","Constant nagging","Instructional minutes lost to management"]', '["Install 3 critical routines next week: entry, transitions, exit"]', '["Three-week routine-establishment coaching cycle."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'I want to be direct and supportive at the same time: your routines is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Routines are the foundation everything else sits on — we need to rebuild this immediately.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (16, 4, 'Students own their behavior, their learning, and their community. The teacher has built student efficacy as a primary goal.', '["Student-led classroom jobs","Students self-correct","Students reflect on behavior and academic work","High internal locus of control visible"]', '["Share student-responsibility practices with the team"]', '["Lead student-agency PD."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"},{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your practice in responsibility reflects mastery-level work that should be named, preserved, and shared with colleagues. Student self-efficacy is Hattie''s #1 effect-size factor — you are investing in exactly the right thing.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (16, 3, 'The teacher is actively developing student self-discipline and responsibility.', '["Student self-assessment happens","Classroom jobs","Reflection on behavior"]', '["Add a weekly self-reflection routine","Add student-led classroom jobs"]', '["Introduce goal-setting and self-monitoring tools."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"},{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your responsibility is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Adding formal student reflection lifts this to Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (16, 2, 'The teacher expects responsibility but hasn''t systematically built it. Many students still need external reminders for basic tasks.', '["Frequent reminders needed","Few self-management structures","Limited student jobs or leadership"]', '["Introduce 2 daily self-management routines (materials, objectives)","Create a class job rotation"]', '["Build one self-management structure at a time over coaching cycles."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'Your responsibility shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Build one self-management routine at a time — materials, then objective tracking, then reflection.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (16, 1, 'Students depend on the teacher for every behavioral decision. There is no student ownership.', '["Students freeze when teacher isn''t directing","No student leadership","No self-regulation practice"]', '["Install one self-management routine this week"]', '["Focus coaching on building one structure at a time."]', '[{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'I want to be direct and supportive at the same time: your responsibility is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Let''s start small — one student-ownership routine per week.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (17, 4, 'The teacher has a deep toolbox of discipline moves and deploys them fluidly so student attention never fully leaves the learning.', '["Non-verbal moves used effectively","Proximity, voice, redirect — all fluid","Pre-corrects visible"]', '["Coach peers on the 3-5 moves you use most"]', '["Let this teacher demo specific moves in PD."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your practice in repertoire reflects mastery-level work that should be named, preserved, and shared with colleagues. Your range of moves is what lets you keep attention without ever raising your voice.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (17, 3, 'The teacher has several reliable discipline moves and uses them to maintain attention.', '["2-3 go-to moves (narration, proximity, pause)","Can capture attention when it slips"]', '["Add 2 new moves from TLAC (e.g., Strong Voice elements, What-To-Do directions)","Practice pre-corrects"]', '["Pick 2 TLAC techniques to install."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your repertoire is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Expanding your toolbox with 2 specific TLAC techniques is the next step.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (17, 2, 'The teacher has a narrow toolbox; students are frequently not paying attention.', '["Over-reliance on raising voice","No non-verbal repertoire","Students coast in and out of attention"]', '["Install What-To-Do directions as a habit","Add narration of positive behavior","Practice Strong Voice elements"]', '["Focused TLAC coaching cycle."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your repertoire shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A narrow toolbox is fixable — let''s install 2 techniques in the next 3 weeks.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (17, 1, 'The teacher struggles to capture attention. There is almost no repertoire.', '["Yelling or pleading","No management techniques visible","Chronic inattention"]', '["Begin daily TLAC technique practice"]', '["Daily coaching support with video review."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'I want to be direct and supportive at the same time: your repertoire is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Building this toolbox is urgent — we will coach specific techniques daily.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (18, 4, 'Every classroom minute produces learning. Coherence, momentum, and transitions are so tight that no time is wasted.', '["Lessons end exactly on time","Transitions under 60 seconds","No dead time"]', '["Share your lesson-flow techniques in PD"]', '["Lead lesson-pacing PD."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your practice in efficiency reflects mastery-level work that should be named, preserved, and shared with colleagues. Your lesson flow is what the Marshall rubric calls "every minute produces learning."');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (18, 3, 'The teacher maximizes learning time through coherence, momentum, and smooth transitions.', '["Transitions under 90 seconds","Pacing is reasonable","Lesson parts connect"]', '["Time every transition for a week — aim for sub-60 seconds","Cut one ritual that doesn''t earn its time"]', '["Use a pacing audit tool."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your efficiency is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Tightening transitions to under 60 seconds is the clearest path up.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (18, 2, 'Significant teaching time is lost to unclear directions, interruptions, and inefficient transitions.', '["Transitions over 2 minutes","Off-topic tangents","Repeating directions"]', '["Pre-write and rehearse directions","Script transitions","Use a timer visible to students"]', '["Pacing coaching cycle with transition tallies."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your efficiency shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Scripting transitions and visible timers usually reclaims 10-15 minutes per day.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (18, 1, 'Most of the class is lost to confusion, interruptions, and ragged transitions. Students are not learning at the rate they should.', '["5+ minute transitions","Frequent off-task stretches","Chronically late starts"]', '["Install a visible timer on day one","Script entry and exit routines"]', '["Daily pacing tallies with coaching debrief."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'I want to be direct and supportive at the same time: your efficiency is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We need to reclaim instructional minutes — this is both a management and a planning issue.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (19, 4, 'The teacher reads the room so well that discipline problems are stopped at the smallest signal — before they ever escalate.', '["Pre-corrects","Subtle proximity and eye contact","Issues never get loud"]', '["Mentor peers on with-it-ness and pre-correcting"]', '["Demo pre-correcting in PD."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your practice in prevention reflects mastery-level work that should be named, preserved, and shared with colleagues. Your with-it-ness (Kounin''s term) is classroom gold — keep it.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (19, 3, 'A confident, dynamic presence stops most problems in the bud.', '["Most issues addressed quickly","Calm, confident tone","Uses proximity and eye contact"]', '["Add pre-corrects at transitions","Practice scanning for 3 seconds at each transition"]', '["With-it-ness coaching cycle."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your prevention is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Adding pre-corrects at every transition sharpens this to Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (19, 2, 'Small issues escalate into bigger ones. The teacher sees problems late.', '["Issues grow before being addressed","Reactive rather than preventive","Misses early signals"]', '["Learn and practice pre-correcting at every transition","Use Strong Voice elements (chin up, pause, don''t talk over)"]', '["Video-based coaching cycle on with-it-ness."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your prevention shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Catching issues earlier is a skill — we can build it in 3 weeks of focused practice.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (19, 1, 'The teacher doesn''t see problems coming, and they escalate routinely.', '["Repeated escalations","Missed early cues","Reactive management only"]', '["Daily video self-review to spot missed cues"]', '["Daily with-it-ness coaching with video."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'I want to be direct and supportive at the same time: your prevention is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Video review will show exactly what you''re missing — we will do it together.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (20, 4, 'Incentives are tied to intrinsic motivation — mastery, purpose, belonging — and students have bought in.', '["Students celebrate growth, not just grades","Public recognition of effort and improvement","Classroom culture of shared success"]', '["Share your incentive framework with the team"]', '["Lead a motivation PD."]', '[{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"},{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your practice in incentives reflects mastery-level work that should be named, preserved, and shared with colleagues. Intrinsic incentives are the hardest to get right — yours are working.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (20, 3, 'Incentives are used wisely to reinforce cooperation and effort.', '["Recognition is specific","Extrinsic rewards used sparingly","Effort praised over ability"]', '["Shift praise language toward specific effort and strategies","Reduce frequency of extrinsic rewards over a month"]', '["Use Dweck''s praise framework in coaching."]', '[{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"}]', 'Your incentives is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. A praise audit (effort-specific vs. ability-general) moves this toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (20, 2, 'Extrinsic rewards dominate. Compliance is being bought rather than built.', '["Constant stickers, points, treats","Praise is generic (\"good job\")","Students focus on rewards not learning"]', '["Shift to process praise (\"you used your strategy\")","Reduce extrinsic rewards gradually over 4 weeks"]', '["Praise-language coaching cycle."]', '[{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"}]', 'Your incentives shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Praise specificity is the fastest lever here — let''s script 10 process-praise sentences together.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (20, 1, 'Extrinsic rewards are given for things already expected, without any link to learning or behavior change.', '["Free time given to keep students quiet","Prizes for compliance","No link to learning"]', '["Stop rewarding expected behavior as a novelty"]', '["Redesign incentive system from scratch with coach."]', '[{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"},{"title":"Responsive Classroom: The Morning Meeting Book","source":"Center for Responsive Schools","type":"book"}]', 'I want to be direct and supportive at the same time: your incentives is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We will rebuild your incentive system — paying for expected behavior creates a bad cycle.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (21, 4, 'The teacher''s expectations are so palpable that every student believes mastery is possible AND expected of them personally.', '["\"You will master this\" language","Individual check-ins with every student","No student treated as hopeless"]', '["Share your expectation-setting language with peers"]', '["Demo high-expectations language in PD."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"}]', 'Your practice in expectations (delivery) reflects mastery-level work that should be named, preserved, and shared with colleagues. Your conviction is contagious — every student hears that you are on their side.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (21, 3, 'The teacher conveys: this is important, you can do it, and I am not going to give up on you.', '["Consistent high-expectations language","Persistence with struggling students","Re-teaching rather than writing off"]', '["Name each student you doubt internally — and plan an expectation-raising move for them","Use \"no opt out\" technique consistently"]', '["No Opt Out coaching cycle."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your expectations (delivery) is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. The No Opt Out technique is a concrete lever that lifts this toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (21, 2, 'The teacher talks about high expectations but lets students off the hook in practice.', '["\"Work hard\" rhetoric but frequent accepts of \"I don''t know\"","Lower questions for lower-performing students","Avoidance of calling on strugglers"]', '["Install No Opt Out next week","Equal distribution of cold calls across the class"]', '["Call-pattern audit in next observation."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your expectations (delivery) shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. No Opt Out and equal call distribution will close the expectations-action gap.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (21, 1, 'The teacher visibly gives up on some students — lower expectations, fewer questions, passive tolerance.', '["\"He''s not going to get it\" mindset","Avoids calling on strugglers","Accepts low-quality work as \"his best\""]', '["Identify the 5 students you have lowest expectations for and plan an expectation-raising move for each"]', '["Intensive coaching cycle on high expectations."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"}]', 'I want to be direct and supportive at the same time: your expectations (delivery) is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. This is a critical area — no student gets written off in our school.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (22, 4, 'The classroom runs on an actively taught growth mindset. Students take risks, learn from mistakes, and own their development.', '["Mistakes celebrated as learning opportunities","Effort and strategy praise (Dweck-aligned)","Students use growth language"]', '["Share your mindset-building protocols with the team"]', '["Lead growth-mindset PD."]', '[{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"},{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your practice in mindset reflects mastery-level work that should be named, preserved, and shared with colleagues. Your mindset work is a permanent gift to every student.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (22, 3, 'The teacher tells students that effective effort, not innate ability, is the key.', '["Process praise","Strategy language","Some explicit mindset teaching"]', '["Add explicit mistake-celebration routines (\"My favorite mistake\")","Teach Dweck''s research to students directly"]', '["Add explicit mindset instruction weekly."]', '[{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"}]', 'Your mindset is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Teaching the research directly to students is the move toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (22, 2, 'The teacher doesn''t counteract fixed-mindset language that shows up in class. Students still say "I''m just not a math person" without pushback.', '["Fixed-mindset student talk goes uncorrected","Ability-based praise (\"you''re so smart\")","Mistakes are awkward"]', '["Interrupt every fixed-mindset statement with a growth reframe","Eliminate ability praise; use process praise only"]', '["Dweck praise-language coaching."]', '[{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"}]', 'Your mindset shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Reframing fixed-mindset talk in the moment is the high-leverage move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (22, 1, 'The teacher communicates a fixed mindset — some students have it, some don''t.', '["\"She''s just not a science kid\" type language","Different expectations by perceived ability","Mistakes treated as failures"]', '["Stop using ability-based language immediately","Begin explicit growth-mindset teaching"]', '["Immediate mindset coaching cycle."]', '[{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"}]', 'I want to be direct and supportive at the same time: your mindset is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Fixed-mindset messaging is harmful; we will replace it with growth-mindset practice.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (23, 4, 'Students know exactly what proficient work looks like — they see essential questions, goals, rubrics, and exemplars.', '["Rubrics posted with exemplars","Students can self-assess against rubrics","Essential questions drive discussion"]', '["Share your exemplar library with the team"]', '["Lead exemplar/rubric PD."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"},{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"}]', 'Your practice in goals reflects mastery-level work that should be named, preserved, and shared with colleagues. Students who can see proficiency can aim at it — your work here is foundational.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (23, 3, 'Unit essential questions and lesson goals are posted; students have a clear sense of purpose.', '["Essential questions posted","Lesson objectives posted","Students can name the goal"]', '["Add exemplars of proficient work","Add rubrics students can self-score against"]', '["Build rubrics with students."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"},{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"}]', 'Your goals is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Adding exemplars alongside goals moves this to Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (23, 2, 'Lesson objectives are stated but not made visible, memorable, or referenced throughout the lesson.', '["Objective said once at start","No visible reference after","Students can''t restate mid-lesson"]', '["Post the objective in student-friendly language","Reference it 3+ times per lesson","End with a check: \"What did we learn today?\""]', '["Objective-visibility coaching cycle."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your goals shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Visibility and repetition of the objective is the quickest win.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (23, 1, 'Lessons start without giving students any sense of what they''re learning or why.', '["No posted objective","No launch or hook","Students can''t describe the learning goal"]', '["Post a student-friendly objective every lesson starting this week"]', '["Daily objective-check for two weeks."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'I want to be direct and supportive at the same time: your goals is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. A posted, student-friendly objective every lesson — that''s the base habit we''ll install.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (24, 4, 'Every lesson hooks students and links new content to what they already know, have experienced, or have read.', '["Strong relevance hooks","Explicit prior-knowledge activation","Cross-lesson connections visible","Student lives and cultures referenced"]', '["Share your hook bank with peers"]', '["Lead hook-design PD."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your practice in connections reflects mastery-level work that should be named, preserved, and shared with colleagues. Your ability to hook students to their own experience is Marzano''s "engaging student interest" at a high level.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (24, 3, 'Prior knowledge is activated and interest is hooked for most students.', '["Opening hook used","Some prior knowledge activation","Connections made when obvious"]', '["Pre-plan a hook for every lesson","Build a hook bank by unit"]', '["Hook-design coaching."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your connections is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Pre-planning every hook (versus reaching for one in the moment) lifts this to Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (24, 2, 'Sometimes the teacher makes it interesting; often the content arrives cold, without prior-knowledge activation.', '["Inconsistent hooks","Prior knowledge not activated","Some lessons land; others feel disconnected"]', '["Add a 30-second hook to every lesson","Use a consistent prior-knowledge routine (KWL, quick-write, brainstorm)"]', '["Hook-and-activate coaching cycle."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your connections shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A 30-second hook and a prior-knowledge routine at the start of every lesson is a 3-week habit shift.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (24, 1, 'Content arrives without connection to student lives or prior learning.', '["No hooks","No prior-knowledge activation","Students see content as disconnected from them"]', '["Add a hook to every lesson starting this week"]', '["Daily hook design for two weeks."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'I want to be direct and supportive at the same time: your connections is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We will script hooks together daily for two weeks to build the habit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (25, 4, 'Explanations are vivid, precise, and memorable. Examples are carefully chosen to illuminate concepts.', '["Precise academic language","Well-chosen examples and non-examples","Vivid analogies that map correctly","Students take notes that mirror clarity"]', '["Share your explanation-design practices with the team"]', '["Let this teacher demo explanations in PD."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"}]', 'Your practice in clarity reflects mastery-level work that should be named, preserved, and shared with colleagues. Clarity at this level is an art — students are learning the content and learning how to explain it.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (25, 3, 'Explanations are clear, language is appropriate, and examples help students learn.', '["Organized explanations","Appropriate vocabulary","Useful examples"]', '["Add non-examples to every concept","Script explanations for the hardest concepts"]', '["Script-and-rehearse coaching cycle."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your clarity is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Scripting explanations for the hardest concepts is the move toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (25, 2, 'Some explanations land; others are fuzzy or confusing. Language is occasionally inappropriate for the age.', '["Rambling explanations","Too much jargon or too little precision","Examples that muddle rather than clarify"]', '["Pre-script your 3 hardest explanations for the coming week","Use the \"3 explanations\" rule: say it 3 different ways"]', '["Explanation-clarity coaching with rehearsal."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"}]', 'Your clarity shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Scripting and rehearsing tough explanations is a practice that pays back all year.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (25, 1, 'Material is regularly presented in confusing ways. Students walk away without understanding.', '["Frequent confusion","Inappropriate language","Students can''t restate"]', '["Begin daily scripting of key explanations"]', '["Daily explanation rehearsal with coach."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'I want to be direct and supportive at the same time: your clarity is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We will script and rehearse your key explanations daily until the habit is installed.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (26, 4, 'The teacher orchestrates a wide range of strategies, materials, and groupings with precision, always matched to the learning need.', '["Multiple modalities per lesson","Fluid grouping","Strategies vary by purpose"]', '["Share your strategy-selection logic with peers"]', '["Lead instructional-strategy PD."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"},{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your practice in repertoire (delivery) reflects mastery-level work that should be named, preserved, and shared with colleagues. Your range of instructional moves is Marzano''s "art" of teaching — named and intentional.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (26, 3, 'Effective strategies, materials, and groupings foster student learning.', '["2-3 strategies per lesson","Flexible grouping used","Appropriate materials selected"]', '["Add a new high-impact strategy from Hattie (jigsaw, Socratic seminar, concept attainment)","Plan groupings with a purpose for each"]', '["High-yield strategy coaching cycle."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"},{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your repertoire (delivery) is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Adding one new high-impact strategy per month builds your toolbox toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (26, 2, 'The strategy range is narrow; same moves repeatedly. Mixed success with reach.', '["Relies on 1-2 strategies","Groupings default to rows or partners only","Some students never reached"]', '["Build a strategy rotation: 5 strategies over the week","Rotate grouping structures"]', '["Strategy-rotation coaching."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your repertoire (delivery) shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A 5-strategy weekly rotation widens your reach fast.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (26, 1, 'Only one or two teaching strategies used; most students are not reached.', '["Lecture-and-worksheet default","No grouping variation","Same type of materials all week"]', '["Install 2 new strategies this month (e.g., turn-and-talk + jigsaw)"]', '["Strategy-expansion coaching cycle."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"},{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'I want to be direct and supportive at the same time: your repertoire (delivery) is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We will install 2 new strategies in the next 4 weeks — starting with turn-and-talk.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (27, 4, 'All students are actively thinking, doing, and problem-solving throughout the lesson.', '["Near-100% participation","Thinking visible in student work during the lesson","Student-to-student discussion substantial"]', '["Share high-engagement routines with the team"]', '["Lead engagement PD."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your practice in engagement (delivery) reflects mastery-level work that should be named, preserved, and shared with colleagues. When every student is doing the cognitive work, you are producing learning at the highest rate possible.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (27, 3, 'Students actively think about, discuss, and use what''s being taught.', '["Most students engaged most of the time","Regular talk and writing","Active tasks"]', '["Move from \"most students\" to \"all students\" via cold call + wait time","Add a written accountability component to every discussion"]', '["Full-participation coaching cycle."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your engagement (delivery) is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Closing the gap from 80% to 100% engagement is the move toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (27, 2, 'Engagement attempts happen, but a meaningful group of students is disengaged.', '["Same students answering","Visible disengagement in 20-30% of the class","Passive stretches"]', '["Install cold call with wait time","Add written-response routines (every student writes)","Track call-ratio for one week"]', '["Engagement-audit coaching cycle."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your engagement (delivery) shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A call-ratio audit and cold-call installation is where we should start.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (27, 1, 'Students are mostly passive — listening to lecture or plodding through worksheets.', '["Most of the class is listening or doing worksheets","Little to no student talk","Low cognitive effort"]', '["Install active participation every 5-7 minutes"]', '["Daily engagement coaching."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'I want to be direct and supportive at the same time: your engagement (delivery) is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Passive instruction is a no-go — we''ll design active moves into every lesson segment.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (28, 4, 'The teacher reaches every student through skillful differentiation and scaffolding on the fly.', '["Scaffolds visible in the moment","Task options matched to readiness","Every student has access to the learning"]', '["Share your scaffolding moves with the team"]', '["Lead differentiation PD."]', '[{"title":"Enhancing Professional Practice: A Framework for Teaching","source":"Charlotte Danielson (ASCD, 2nd ed.)","type":"book"}]', 'Your practice in differentiation (delivery) reflects mastery-level work that should be named, preserved, and shared with colleagues. Your in-the-moment differentiation meets students where they are and moves them forward.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (28, 3, 'Instruction is scaffolded to accommodate most students'' learning needs.', '["Scaffolds present for most students","Some task options","IEP/504 accommodations honored"]', '["Add a scaffold for your highest-need learners in every lesson","Add an extension for your highest-readiness learners"]', '["Readiness-data-based differentiation coaching."]', '[{"title":"Enhancing Professional Practice: A Framework for Teaching","source":"Charlotte Danielson (ASCD, 2nd ed.)","type":"book"}]', 'Your differentiation (delivery) is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Planning specific scaffolds for your highest and lowest learners lifts this.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (28, 2, 'The teacher attempts to accommodate but with mixed success. Differentiation is inconsistent.', '["Some scaffolds for IEP students","No other differentiation","One-size-fits-most tasks"]', '["For the next three lessons, name one scaffold and one extension you''ll deploy","Use pre-assessment data to flex tasks"]', '["Scaffold-and-extend coaching."]', '[{"title":"Enhancing Professional Practice: A Framework for Teaching","source":"Charlotte Danielson (ASCD, 2nd ed.)","type":"book"}]', 'Your differentiation (delivery) shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Explicit scaffolds and extensions — written into the lesson plan — closes most of this gap.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (28, 1, 'No differentiation. Students with learning deficits are left behind.', '["Identical tasks for all","No scaffolds","No extensions","No flexible grouping"]', '["Begin adding one scaffold and one extension to every lesson"]', '["Three-week intensive differentiation cycle."]', '[{"title":"Enhancing Professional Practice: A Framework for Teaching","source":"Charlotte Danielson (ASCD, 2nd ed.)","type":"book"},{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'I want to be direct and supportive at the same time: your differentiation (delivery) is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Every learner deserves access — we will build differentiation lesson by lesson.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (29, 4, 'The teacher is a masterful improviser — catches teachable moments and deftly repairs misunderstandings as they emerge.', '["Adapts lessons mid-flight","Addresses misconceptions the moment they surface","Uses student thinking to deepen the lesson"]', '["Share your flexibility strategies with the team"]', '["Demo responsive teaching in PD."]', '[{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"},{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your practice in nimbleness reflects mastery-level work that should be named, preserved, and shared with colleagues. Your ability to flex the lesson based on student thinking is master-teacher work.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (29, 3, 'The teacher modifies lessons when teachable moments arise.', '["Some on-the-fly adjustments","Responds to student thinking when obvious","Willing to pause the plan"]', '["Plan branching paths in advance for likely student responses","Practice \"parking\" off-topic questions productively"]', '["Responsive-teaching coaching."]', '[{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"}]', 'Your nimbleness is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Pre-planned branches sharpen your nimbleness.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (29, 2, 'Teachable moments are often missed because the teacher is locked into the plan.', '["Plan drives over student thinking","Teachable moments waved off","Limited on-the-fly repair"]', '["Rehearse noticing: practice spotting 2 teachable moments per day","Plan 1 \"if-then\" contingency per lesson"]', '["Observation-and-notice coaching cycle."]', '[{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"}]', 'Your nimbleness shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Training yourself to notice — and then pausing the plan — is the work.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (29, 1, 'The lesson plan is followed rigidly. Students'' thinking and confusion are bypassed.', '["Sticks to script regardless of student cues","Ignores confusion","Misses every teachable moment"]', '["Plan one \"I will pause here if students X\" contingency per lesson"]', '["Plan-with-branches coaching cycle."]', '[{"title":"The Skillful Teacher","source":"Saphier, Haley-Speca, & Gower (RBT, 7th ed.)","type":"book"}]', 'I want to be direct and supportive at the same time: your nimbleness is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We will plan branches into your lessons — that''s how nimbleness becomes a habit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (30, 4, 'Every lesson ends with students summarizing, internalizing, and transferring learning to real-life or novel contexts.', '["Consistent closure routines","Real-life application tasks","Transfer questions asked"]', '["Share your closure protocols with peers"]', '["Lead closure-design PD."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"},{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your practice in application reflects mastery-level work that should be named, preserved, and shared with colleagues. Strong closure is what makes learning stick — keep doing it every lesson.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (30, 3, 'Students sum up what they learned and apply it in a different context.', '["Closure happens most lessons","Application tasks present","Exit tickets used"]', '["Add a transfer prompt to every lesson (how does this connect to X?)","Use a 3-2-1 protocol"]', '["Closure-variety coaching."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your application is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. A transfer prompt at closure moves this toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (30, 2, 'Some closure happens, but it''s inconsistent and application is weak.', '["Closure skipped when lesson runs long","Application is limited to \"homework\"","No summarization by students"]', '["Guarantee 3 minutes of closure in every lesson","Use an exit ticket daily"]', '["Closure-habit coaching cycle."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your application shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Protect the last 3 minutes of every lesson for student-led summary — that''s the habit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (30, 1, 'Lessons end when the bell rings. No closure, no application.', '["Abrupt endings","No exit ticket or summary","No transfer to other contexts"]', '["Install a 60-second exit ticket every single day this week"]', '["Daily closure check."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'I want to be direct and supportive at the same time: your application is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Closure is non-negotiable — we will build the habit starting this week.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (31, 4, 'Students internalize the criteria for proficient work. They use rubrics and exemplars to self-direct their learning.', '["Rubrics posted and used by students","Exemplars visible","Students describe proficiency in their own words"]', '["Share your exemplar library with the team"]', '["Lead rubric-internalization PD."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your practice in criteria reflects mastery-level work that should be named, preserved, and shared with colleagues. Students who can see proficiency can self-correct — this work is foundational to self-directed learners.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (31, 3, 'Rubrics and exemplars are posted; students can see what proficient work looks like.', '["Rubrics posted for major work","Exemplars shown","Students reference them"]', '["Have students co-create a rubric for one task per unit","Use rubrics for peer feedback"]', '["Co-created-rubric coaching."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your criteria is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Co-creating rubrics with students moves this toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (31, 2, 'The teacher tells students some qualities of good work, but proficiency is mostly implicit.', '["Verbal criteria only","No posted rubrics","Unclear expectations for finished work"]', '["Create a rubric for every major task","Share exemplars before the task, not after"]', '["Rubric-building coaching."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your criteria shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Posted rubrics and pre-task exemplars are quick wins.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (31, 1, 'Students have to guess what counts as good work.', '["No rubrics","No exemplars","Grading surprises students"]', '["Build a rubric for the next major task before assigning it"]', '["Rubric-establishment coaching cycle."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'I want to be direct and supportive at the same time: your criteria is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Rubrics are non-negotiable — we will build one for your next task together.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (32, 4, 'Every unit begins with a carefully designed diagnostic that the teacher uses to shape instruction.', '["Pre-assessments planned and analyzed","Instruction adjusted based on data","Students see how the pre-assessment guides the unit"]', '["Share your diagnostic protocols"]', '["Lead pre-assessment PD."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"},{"title":"Understanding by Design","source":"Wiggins & McTighe (ASCD, 2005)","type":"book"}]', 'Your practice in diagnosis reflects mastery-level work that should be named, preserved, and shared with colleagues. Your diagnostic work is what Wiliam calls "assessment for learning" — not assessment of it.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (32, 3, 'The teacher diagnoses students'' knowledge up front and makes small adjustments.', '["Pre-assessment used","Some adjustments made","Data referenced"]', '["Make the adjustments bigger — flex groupings or re-order based on data","Share the data with students"]', '["Data-based adjustment coaching."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your diagnosis is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Bigger moves on the data — regrouping, re-sequencing — lifts this toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (32, 2, 'A quick KWL happens, but data isn''t really used to shape instruction.', '["KWL or similar used","Data not analyzed","Instruction proceeds as planned regardless"]', '["Design a true diagnostic for the next unit","Commit to one instructional adjustment based on data"]', '["Diagnostic-design coaching."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your diagnosis shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A real diagnostic (not just KWL) and one adjustment based on it is the move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (32, 1, 'Instruction begins without diagnosing what students know. Misconceptions and gaps are not identified.', '["No pre-assessment","No adjustment to plans"]', '["Add a diagnostic to the next unit, starting next week"]', '["Pre-assessment coaching cycle."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'I want to be direct and supportive at the same time: your diagnosis is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Diagnosing before teaching is the most basic assessment-for-learning move — we will install it.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (33, 4, 'The teacher has a variety of highly effective checks for understanding and immediately repairs confusion.', '["Multiple CFU techniques used","Data collected from every student, not just raised hands","Immediate repair of confusion"]', '["Share your CFU toolkit with peers"]', '["Lead CFU PD."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"},{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'Your practice in on-the-spot reflects mastery-level work that should be named, preserved, and shared with colleagues. Your checking-for-understanding work is the engine of responsive teaching.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (33, 3, 'Frequent checks for understanding and useful feedback when students are confused.', '["Regular CFU","Feedback given in response","Some student data gathered"]', '["Add all-student techniques (white boards, hand signals, exit tickets)","Move from thumb-ups to written response"]', '["All-student-response coaching."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your on-the-spot is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Move from visible-CFU to all-student-written-CFU for the upgrade.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (33, 2, 'The teacher uses mediocre CFU techniques (thumbs up, thumbs down) that don''t reveal individual student understanding.', '["Group-level signals only","Same few students confirm understanding","Many students slip through"]', '["Install individual response techniques (white boards, written 1-sentence responses)","Cold call with \"everyone writes first\""]', '["CFU-upgrade coaching cycle."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"},{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your on-the-spot shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Thumbs-up isn''t enough — let''s install whiteboards or written CFU.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (33, 1, 'Checks are perfunctory ("Everyone with me?") and reveal nothing about individual student thinking.', '["\"Any questions?\" as CFU","No data gathered","Students slip through undetected"]', '["Install one all-student CFU technique this week (whiteboards or exit tickets)"]', '["Daily CFU coaching."]', '[{"title":"Teach Like a Champion 3.0","source":"Doug Lemov (Jossey-Bass, 2021)","type":"book"}]', 'I want to be direct and supportive at the same time: your on-the-spot is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. "Everyone with me?" is not a check — we will install a real one this week.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (34, 4, 'Students set ambitious goals, continuously self-assess, and always know where they stand academically.', '["Student-owned data notebooks","Regular self-assessment routines","Goal-setting visible"]', '["Share your self-assessment system with the team"]', '["Lead student-agency PD."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"},{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your practice in self-assessment reflects mastery-level work that should be named, preserved, and shared with colleagues. Student self-reported grades/self-assessment is Hattie''s #1 effect size — you are investing in the highest-leverage skill.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (34, 3, 'Students set goals, self-assess, and take responsibility for improving performance.', '["Goal-setting happens","Self-assessment routines in place","Student reflection present"]', '["Add student data notebooks","Move from unit-level to daily self-assessment"]', '["Student data-notebook coaching."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"},{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your self-assessment is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Daily self-assessment and student-owned data builds toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (34, 2, 'The teacher urges students to look over their work, but self-assessment isn''t systemic.', '["Occasional self-checking","No self-assessment structure","Rare goal-setting"]', '["Install a weekly goal-setting routine","Add a daily \"how did I do?\" reflection"]', '["Self-assessment structure coaching."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your self-assessment shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Weekly goal-setting and daily reflection is the infrastructure we need to build.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (34, 1, 'Students move on without self-assessment. There is no reflection or ownership.', '["No self-assessment","No goal setting","Students don''t know how they''re doing"]', '["Install a weekly self-check routine"]', '["Build self-assessment from scratch."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'I want to be direct and supportive at the same time: your self-assessment is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Self-assessment is the biggest lever available — we will install it.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (35, 4, 'Student work is regularly celebrated with rubrics and commentary, showing what proficient looks like and how to improve.', '["Frequent displays of student work with commentary","Rubric-based feedback visible","Recognition tied to growth"]', '["Share your recognition practices"]', '["Lead work-display PD."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"},{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"}]', 'Your practice in recognition reflects mastery-level work that should be named, preserved, and shared with colleagues. Your recognition practices make proficiency visible and motivate effort.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (35, 3, 'Student work is regularly posted to make progress visible.', '["Student work posted","Some commentary","Linked to standards"]', '["Add rubric commentary to each displayed piece","Post a range of work, not only top work"]', '["Growth-focused display coaching."]', '[{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"}]', 'Your recognition is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Show the range of work with commentary — not just the top — to move toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (35, 2, 'Only "A" student work is posted, which sends the wrong message.', '["Only top work displayed","No commentary","Fixed-mindset vibe"]', '["Display a range of work showing growth","Add specific growth commentary"]', '["Growth-display coaching."]', '[{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"}]', 'Your recognition shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Showing growth trajectories (not just end products) builds a growth-mindset culture.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (35, 1, 'Little or no student work is displayed. Students don''t see themselves in the classroom.', '["Blank walls","No student work posted"]', '["Post student work this week, with rubric commentary"]', '["Recognition coaching cycle."]', '[{"title":"Mindset: The New Psychology of Success","source":"Carol Dweck (Ballantine, 2006)","type":"book"}]', 'I want to be direct and supportive at the same time: your recognition is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Students should see their own work on the walls — let''s start this week.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (36, 4, 'The teacher works with colleagues to use interim data to fine-tune teaching, re-teach, and help struggling students.', '["PLC data conversations","Data-driven re-teaching","Targeted intervention for strugglers"]', '["Lead the data-team process"]', '["Invite to lead data-team PD."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"},{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"}]', 'Your practice in interims reflects mastery-level work that should be named, preserved, and shared with colleagues. Your data-team work is the heart of continuous improvement.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (36, 3, 'Interim assessment data is used to adjust teaching, re-teach, and follow up with failing students.', '["Data analyzed after interims","Re-teaching happens","Follow-up for strugglers"]', '["Move data analysis from individual to team-based","Deepen root-cause analysis"]', '["Data-team protocol coaching."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your interims is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Joining a team data protocol moves this to Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (36, 2, 'The teacher looks over tests but doesn''t deeply analyze or follow up.', '["Surface-level review","Minimal re-teaching","No intervention for strugglers"]', '["Use an item-analysis protocol on the next interim","Build one targeted re-teach plan per interim"]', '["Item-analysis coaching cycle."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your interims shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Item analysis and targeted re-teach is the big move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (36, 1, 'Tests are given and the class moves on. No analysis, no follow-up.', '["No item analysis","No re-teaching","No intervention"]', '["After every assessment: pick 3 items to re-teach based on class performance"]', '["Data-review coaching."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'I want to be direct and supportive at the same time: your interims is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Assessment without follow-up is wasted data — we will build the habit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (37, 4, 'The teacher relentlessly follows up with struggling students — with personal attention until they reach proficiency.', '["Individual re-teaching sessions","Relationship-based follow-up","Students who were struggling are now proficient"]', '["Share your follow-up protocols"]', '["Lead intervention PD."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your practice in tenacity reflects mastery-level work that should be named, preserved, and shared with colleagues. Your tenacity is the reason your struggling students catch up.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (37, 3, 'The teacher takes responsibility for struggling students and gives them extra help.', '["Extra help offered","Struggling students tracked","Some improvement visible"]', '["Create a standing weekly intervention block","Track specific skill growth for each struggler"]', '["Intervention-tracking coaching."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your tenacity is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Tracking each struggler''s specific skill growth is the move toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (37, 2, 'The teacher offers re-takes, but doesn''t fundamentally change the learning plan for students who are failing.', '["Re-takes offered","No root-cause analysis","Struggling students stay struggling"]', '["Beyond re-takes: identify what specifically each struggler needs and re-teach it","Install a weekly intervention block"]', '["Root-cause coaching for struggling students."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your tenacity shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Re-takes aren''t enough — root-cause re-teaching is the move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (37, 1, 'The teacher communicates that if a student fails, the class moves on.', '["No follow-up","Visible \"they failed, my problem is done\" attitude"]', '["Build intervention time into every week starting now"]', '["Intervention-design coaching."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"},{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"}]', 'I want to be direct and supportive at the same time: your tenacity is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. No student gets left behind — we will build intervention time immediately.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (38, 4, 'Students who need specialized support get it immediately — the teacher is an active partner with specialists.', '["Timely referrals","Active collaboration with specialists","Data shared with support teams"]', '["Share your referral process with the team"]', '["Lead MTSS coordination."]', '[{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"}]', 'Your practice in support reflects mastery-level work that should be named, preserved, and shared with colleagues. Your referral and collaboration practices make the support system work for kids.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (38, 3, 'The teacher refers students for specialized diagnosis when needed.', '["Appropriate referrals","Some collaboration with specialists"]', '["Move from referral to active collaboration with specialists","Build a tier-1 intervention plan before referring"]', '["MTSS coaching."]', '[{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"}]', 'Your support is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Active collaboration with specialists is the upgrade.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (38, 2, 'Referrals are late, or students who don''t need them are referred.', '["Over-referral or under-referral","No tier-1 data before referral","Referrals feel random"]', '["Build a tier-1 intervention and data-collection step before referral","Use a consistent referral protocol"]', '["Referral-protocol coaching."]', '[{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"}]', 'Your support shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A data-backed referral process is the move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (38, 1, 'Referral patterns are broken — students who need support don''t get it, and students who don''t are sent anyway.', '["Chronically mistimed referrals","No data behind referrals"]', '["Adopt the school referral protocol immediately"]', '["Referral-process coaching."]', '[{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"}]', 'I want to be direct and supportive at the same time: your support is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We need to reset your referral process with the school MTSS team.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (39, 4, 'The teacher works with colleagues to analyze and chart data, draw action conclusions, and leverage student growth.', '["Team-based data analysis","Visible action conclusions","Data drives decisions"]', '["Lead team data analysis"]', '["Invite to lead data PD."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"},{"title":"Rethinking Teacher Supervision and Evaluation","source":"Kim Marshall (Jossey-Bass, 2009)","type":"book"}]', 'Your practice in analysis reflects mastery-level work that should be named, preserved, and shared with colleagues. Your data-analysis work keeps the team honest and growing.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (39, 3, 'The teacher analyzes data, draws conclusions, and shares appropriately.', '["Data analyzed","Conclusions drawn","Some sharing"]', '["Move to collaborative analysis","Chart data so it''s visible"]', '["Collaborative data coaching."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your analysis is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Moving to collaborative analysis builds toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (39, 2, 'Grades get recorded, some patterns noticed, but no action taken on them.', '["Gradebook up to date","No formal analysis","No action plan"]', '["Use an item-analysis protocol at least twice per unit","Build one action plan per data review"]', '["Item-analysis coaching cycle."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your analysis shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Data without action plans is just record-keeping — let''s add the action step.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (39, 1, 'Grades are recorded and instruction moves on. No analysis happens.', '["Gradebook only","No analysis","No patterns identified"]', '["Start a weekly 15-minute data review habit"]', '["Data-habit coaching."]', '[{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'I want to be direct and supportive at the same time: your analysis is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We will build a simple weekly data-review habit together.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (40, 4, 'The teacher reflects with colleagues on what worked and continuously improves instruction.', '["Regular reflection in PLCs","Documented lesson refinements","Evidence of improvement over time"]', '["Share your reflection protocols with the team"]', '["Lead reflective-practice PD."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"},{"title":"The Impact Cycle","source":"Jim Knight (Corwin, 2017)","type":"book"}]', 'Your practice in reflection reflects mastery-level work that should be named, preserved, and shared with colleagues. Reflection is the engine of teacher growth — yours is serious and structured.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (40, 3, 'The teacher reflects on lessons and units and continuously works to improve them.', '["Individual reflection visible","Some lesson refinements","Growth over time"]', '["Move to collaborative reflection","Keep a formal reflection journal"]', '["Reflective-practice coaching."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your reflection is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Adding a collaborative reflection structure takes this to Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (40, 2, 'Reflection happens at the end of a unit or semester but not systematically.', '["Occasional reflection","No written record","Sporadic improvements"]', '["Install a weekly 10-minute reflection routine","Keep a brief digital journal"]', '["Build reflection routine."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your reflection shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A weekly reflection habit is the structural upgrade.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (40, 1, 'When teaching is unsuccessful, no lessons are drawn for the future. Mistakes are repeated.', '["No reflection","Patterns of ineffective teaching repeated"]', '["Begin a weekly reflection habit this week"]', '["Reflection-habit coaching."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'I want to be direct and supportive at the same time: your reflection is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Reflection is how you keep growing — we will install a weekly habit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (41, 4, 'The teacher shows great sensitivity and respect for family and community culture, values, and beliefs.', '["Cultural knowledge visible in curriculum","Parent-culture sensitivity in communication","Community values honored"]', '["Share cultural-responsiveness practices with team"]', '["Lead cultural-responsiveness PD."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your practice in family respect reflects mastery-level work that should be named, preserved, and shared with colleagues. Your cultural responsiveness is a model for the school.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (41, 3, 'The teacher communicates respectfully with parents and is sensitive to different families'' cultures.', '["Respectful tone","Awareness of diverse backgrounds","Culturally sensitive communication"]', '["Build a family-information card with cultural notes","Include home-language communication when needed"]', '["Family-context coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your family respect is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. A systematic approach to learning family context lifts this toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (41, 2, 'The teacher tries to be sensitive but sometimes shows lack of awareness.', '["Occasional missteps","Generic communication","Limited awareness of family diversity"]', '["Learn basic family-context information for each student","Review communications for cultural sensitivity"]', '["Cultural-responsiveness coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your family respect shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Building awareness of each family''s context closes this gap.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (41, 1, 'The teacher is often insensitive to the culture and beliefs of students'' families.', '["Dismissive of cultural differences","Assumes all families are alike","Insensitive communications"]', '["Begin building family-context profiles","Review all parent communications before sending"]', '["Immediate cultural-responsiveness coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'I want to be direct and supportive at the same time: your family respect is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Cultural responsiveness is foundational to serving our families — we will build it intentionally.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (42, 4, 'The teacher shows each parent in-depth knowledge of their child and strong belief in their potential.', '["Personalized parent conversations","Belief language used","Parents feel known"]', '["Share your parent-communication practices with team"]', '["Lead parent-conference PD."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your practice in belief reflects mastery-level work that should be named, preserved, and shared with colleagues. Parents who feel their child is known and believed-in are your strongest partners.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (42, 3, 'The teacher shows genuine interest and belief in each child reaching standards.', '["Individual interest shown","Positive messaging to parents"]', '["Move from \"I care\" to \"I know\" — share specific student achievements regularly","Build a brief note home each week for 5 families"]', '["Specific-parent-communication coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your belief is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Moving from generic care to specific knowledge in parent communication is the next step.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (42, 2, 'The teacher tells parents they care, but communication is generic.', '["Form-letter style communication","Generic \"your child\" messaging","Limited specifics"]', '["Personalize every parent communication with specifics","Share one concrete student achievement per communication"]', '["Personalization coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your belief shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Specificity in parent communication is the high-leverage move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (42, 1, 'Parents don''t see belief or concern in the teacher''s communication.', '["No personalized communication","No expression of belief"]', '["Send a specific, positive communication about each student this month"]', '["Parent-communication coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'I want to be direct and supportive at the same time: your belief is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Every family needs to hear you believe in their child — we will design this in.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (43, 4, 'Parents receive clear, user-friendly expectations and exemplars of proficient work.', '["Exemplars shared","Student-friendly expectations","Parent guides to curriculum"]', '["Share parent guide with team"]', '["Lead parent-guide design PD."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your practice in family expectations reflects mastery-level work that should be named, preserved, and shared with colleagues. Parents who see exemplars can support their children in specific ways.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (43, 3, 'Parents get clear learning and behavior expectations for the year.', '["Back-to-school night communication","Syllabus shared","Expectations clear"]', '["Add exemplars of proficient work to parent communication","Update expectations mid-year"]', '["Exemplar-for-parents coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your family expectations is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Adding exemplars to parent communication is the move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (43, 2, 'Parents get the rules and syllabus but no real guidance on what proficient work looks like.', '["Rules sheet sent home","No work exemplars","Limited curriculum communication"]', '["Build a parent-friendly curriculum guide","Share exemplars of proficient work"]', '["Parent-guide coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your family expectations shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A parent-friendly curriculum guide lifts this quickly.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (43, 1, 'Parents aren''t informed about learning or behavior expectations.', '["No communication","Parents don''t know what''s happening in class"]', '["Send a unit overview to parents before each unit starting this week"]', '["Parent-communication basics coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'I want to be direct and supportive at the same time: your family expectations is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Parents need this baseline communication — we will build the habit now.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (44, 4, 'Parents hear positive news first AND are immediately informed about problems.', '["Regular positive communication","Prompt problem notification","Balanced messaging"]', '["Share your communication cadence with team"]', '["Lead parent-communication PD."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your practice in communication reflects mastery-level work that should be named, preserved, and shared with colleagues. Your communication cadence builds trust with families.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (44, 3, 'The teacher promptly informs parents of problems and also shares good news.', '["Two-way communication","Balance of positive and concern","Timely outreach"]', '["Adopt a 2:1 positive-to-concern ratio","Log parent contacts"]', '["Communication-ratio coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your communication is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. A 2:1 positive-to-concern ratio in parent contacts is the refinement.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (44, 2, 'Parents hear from the teacher mostly about problems.', '["Heavy concern-focused communication","Little positive outreach","Parents feel targeted"]', '["Send 3 positive notes per week before any concern note","Track your communication ratio"]', '["Positive-communication coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your communication shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Leading with positive news changes the entire parent relationship.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (44, 1, 'Parents rarely hear from the teacher about anything — concerns or good news.', '["Silent communication pattern","Parents surprised by grades","No relationship"]', '["Commit to a weekly positive contact with 5 families"]', '["Parent-communication habit coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'I want to be direct and supportive at the same time: your communication is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We will build a weekly parent-communication habit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (45, 4, 'Parents are regularly involved in supporting and enriching the curriculum as it unfolds.', '["Weekly curriculum updates","Home-learning extensions","Parent volunteers"]', '["Share parent-involvement strategies"]', '["Lead parent-involvement PD."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your practice in involving reflects mastery-level work that should be named, preserved, and shared with colleagues. Your parent partnership is a real lever for student learning.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (45, 3, 'The teacher updates parents on the curriculum and suggests home-support.', '["Curriculum updates","Home-learning suggestions"]', '["Move from \"here''s what''s happening\" to \"here''s how you can help\"","Include parent-friendly home activities"]', '["Home-learning coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your involving is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Shifting from informing to activating parents is the upgrade.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (45, 2, 'Occasional home-support suggestions but no systematic involvement.', '["Occasional take-home activities","No structured involvement"]', '["Build weekly home-learning extension","Include parent tips in communications"]', '["Home-support coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your involving shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A weekly structured home-learning extension is the move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (45, 1, 'The teacher rarely communicates with parents about helping at home.', '["No home-support communication","Parents uninvolved"]', '["Send one home-learning tip per week starting now"]', '["Parent-involvement coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'I want to be direct and supportive at the same time: your involving is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Parents want to help — we will give them specific, doable ways.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (46, 4, 'Homework is engaging, return rates are near 100%, and feedback is prompt and helpful.', '["Engaging assignments","95%+ return","Feedback within 48 hours"]', '["Share your homework design with team"]', '["Lead homework-design PD."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"},{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your practice in homework reflects mastery-level work that should be named, preserved, and shared with colleagues. Your homework system actually advances learning rather than punishing or pretending.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (46, 3, 'Homework is appropriate, students are accountable, and the teacher gives feedback.', '["Appropriate assignments","Accountability measures","Feedback given"]', '["Tighten homework to 10-15 minutes of high-leverage practice per day","Shorten the feedback loop"]', '["Homework-purpose coaching."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your homework is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Homework with a clear purpose and quick feedback lifts this.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (46, 2, 'Homework is assigned and tracked but rarely followed up.', '["Compliance tracked","No meaningful feedback","Quality of homework unclear"]', '["Give feedback within 48 hours","Use homework data to inform re-teaching"]', '["Homework-feedback coaching."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'Your homework shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Homework without feedback is a missed opportunity — we will install the feedback step.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (46, 1, 'The teacher assigns homework but accepts that many students won''t turn it in.', '["Low return rate","No follow-up","Homework feels meaningless"]', '["Redesign homework so it''s clearly connected to next-day instruction","Build accountability with feedback"]', '["Homework-redesign coaching."]', '[{"title":"The Art and Science of Teaching","source":"Robert Marzano (ASCD, 2007)","type":"book"}]', 'I want to be direct and supportive at the same time: your homework is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Low-return homework signals we need to redesign the purpose and system.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (47, 4, 'The teacher deals immediately and successfully with parent concerns, making parents feel welcome anytime.', '["Same-day response to parents","Parents feel genuinely welcomed","Issues resolved quickly"]', '["Share your responsiveness standards with team"]', '["Lead parent-responsiveness PD."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your practice in responsiveness reflects mastery-level work that should be named, preserved, and shared with colleagues. Parents who feel welcomed are your best advocates.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (47, 3, 'The teacher responds promptly to parent concerns and makes parents feel welcome.', '["24-48 hour response","Welcoming tone","Issues addressed"]', '["Commit to same-day responses when possible","Track response times"]', '["Response-time coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your responsiveness is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Same-day responses move this to Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (47, 2, 'The teacher is sometimes slow to respond and can come across as unwelcoming.', '["Delayed responses","Occasional cold tone","Parents feel hesitant to reach out"]', '["Set a 24-hour response standard","Review communication tone"]', '["Tone-and-timing coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your responsiveness shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A 24-hour response standard and tone review closes this gap.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (47, 1, 'The teacher doesn''t respond to parents, and parents feel unwelcome.', '["Ignored communications","Parents feel blocked"]', '["Respond to all parent communications within 24 hours starting this week"]', '["Response-habit coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'I want to be direct and supportive at the same time: your responsiveness is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Every parent communication gets a response within 24 hours — that''s our standard.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (48, 4, 'The teacher uses student-led conferences, report cards, and informal talks to give parents detailed feedback.', '["Student-led conferences","Detailed progress reports","Informal check-ins"]', '["Share your conference approach with team"]', '["Lead student-led conference PD."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"},{"title":"Embedded Formative Assessment","source":"Dylan Wiliam (Solution Tree, 2nd ed., 2018)","type":"book"}]', 'Your practice in reporting reflects mastery-level work that should be named, preserved, and shared with colleagues. Student-led conferences are the gold standard — keep this practice.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (48, 3, 'Conferences and report cards give parents feedback on progress.', '["Regular conferences","Detailed report cards","Clear feedback"]', '["Move toward student-led conferences","Add mid-quarter progress communication"]', '["Conference-structure coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your reporting is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Moving toward student-led conferences is the path to Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (48, 2, 'Conferences tell parents where their child can improve, but details are thin.', '["Surface-level feedback","Limited data shared","Focus only on weaknesses"]', '["Prepare data-rich conference materials","Balance strengths and growth areas"]', '["Conference-preparation coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your reporting shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Data-rich, balanced conferences are the move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (48, 1, 'Report cards go home; parents are expected to figure out the rest.', '["No conferences held","No follow-up","Parents surprised by grades"]', '["Hold a conference for every student this quarter"]', '["Conference-establishment coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'I want to be direct and supportive at the same time: your reporting is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Regular conferences are a baseline — we will establish them.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (49, 4, 'The teacher successfully contacts and works with all parents, including those hard to reach.', '["100% family contact","Tenacious with hard-to-reach","Home visits or flexible meeting times"]', '["Share your outreach strategies with team"]', '["Lead hard-to-reach outreach PD."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your practice in outreach reflects mastery-level work that should be named, preserved, and shared with colleagues. Reaching all families — especially the hardest to reach — is the deepest equity work.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (49, 3, 'The teacher tries to contact all parents and is tenacious with hard-to-reach families.', '["Broad outreach","Multiple attempts for hard-to-reach","Most families contacted"]', '["Offer evening or home visit options","Use multiple communication channels"]', '["Channel-diversification coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your outreach is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Multiple channels and flexible timing closes the last gap.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (49, 2, 'Most of the teacher''s contact is with high-achieving students'' parents.', '["Lopsided contact","Limited hard-to-reach outreach","Unequal relationships"]', '["List your 5 least-contacted families and reach out to them this month","Diversify outreach channels"]', '["Equity-of-outreach coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your outreach shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Targeting the families you don''t hear from is the equity move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (49, 1, 'Little or no effort to contact parents.', '["No family outreach","No family relationships"]', '["Contact every family this month"]', '["Outreach-establishment coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'I want to be direct and supportive at the same time: your outreach is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. We will establish family outreach as a core habit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (50, 4, 'The teacher successfully enlists classroom volunteers and extra resources from homes and the community.', '["Regular classroom volunteers","Community resources integrated","Parent expertise utilized"]', '["Share your resource-building practices"]', '["Lead community-resource PD."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your practice in resources reflects mastery-level work that should be named, preserved, and shared with colleagues. Your community-resource network strengthens learning for all students.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (50, 3, 'The teacher reaches out to families and community agencies for volunteers and additional resources.', '["Some volunteers","Some community connections","Occasional resource-gathering"]', '["Systematize volunteer recruitment","Build a community-resource map"]', '["Resource-mapping coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your resources is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. A systematized approach to volunteers and resources is the move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (50, 2, 'The teacher asks for occasional parent involvement but doesn''t actively build a resource network.', '["One-off volunteer requests","No community partnerships"]', '["Build one new community partnership this semester","Invite one volunteer per month"]', '["Partnership-building coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'Your resources shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Intentional partnership-building is the upgrade.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (50, 1, 'The teacher doesn''t reach out for extra support from parents or the community.', '["No volunteers","No community connections"]', '["Invite one parent volunteer this month"]', '["Outreach-habit coaching."]', '[{"title":"School, Family, and Community Partnerships","source":"Joyce Epstein (Corwin)","type":"book"}]', 'I want to be direct and supportive at the same time: your resources is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Even one volunteer per month changes a classroom — we will start there.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (51, 4, 'Perfect or near-perfect attendance (98-100%).', '["Attends nearly every scheduled day","Plans ahead for known absences","Models reliability for students"]', '["Continue current patterns"]', '["Preserve and honor this reliability."]', '[]', 'Your practice in attendance reflects mastery-level work that should be named, preserved, and shared with colleagues. Your presence is felt and your students are benefiting.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (51, 3, 'Very good attendance (95-97%).', '["Reliable presence","Absences communicated appropriately"]', '["Continue patterns","Plan ahead for known absences"]', '[]', '[]', 'Your attendance is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Your attendance reliability is professional and appreciated.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (51, 2, 'Moderate absences (6-10%).', '["6-10% absence rate","Pattern is noticeable"]', '["Review absence patterns with principal","Build proactive sub-plans for known absence days"]', '["Attendance-planning conversation."]', '[]', 'Your attendance shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Attendance pattern needs attention — let''s discuss extenuating circumstances if any.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (51, 1, 'Many absences (11%+).', '["Absence rate 11% or higher","Impact on student learning"]', '["Immediate conversation with principal","Review FMLA/ADA/personal situation"]', '["Formal attendance improvement plan."]', '[]', 'I want to be direct and supportive at the same time: your attendance is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. This level of absence impacts students — we need to discuss circumstances and a plan.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (52, 4, 'In professional contexts, the teacher speaks and writes correctly, succinctly, and eloquently.', '["Polished written communication","Precise verbal communication","Models strong language for students"]', '["Continue modeling"]', '["Share polished communication as a model."]', '[]', 'Your practice in language reflects mastery-level work that should be named, preserved, and shared with colleagues. Your professional language models for students what academic fluency sounds like.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (52, 3, 'Correct grammar, syntax, usage, and spelling in professional contexts.', '["Generally correct language","Professional tone"]', '["Use grammar-check tools for high-stakes communication","Proofread before sending"]', '[]', '[]', 'Your language is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Your professional language is solid — maintain it.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (52, 2, 'Periodic errors in grammar, syntax, usage, or spelling.', '["Occasional errors","Communications need proofreading"]', '["Always use a grammar-check tool","Ask a colleague to proof important communications"]', '["Writing-check coaching."]', '[]', 'Your language shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Consistent use of grammar-check tools closes this gap.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (52, 1, 'Frequent errors in professional language.', '["Regular errors in written communication","Unprofessional tone"]', '["Required proofreading of all communications by principal for a period"]', '["Professional-writing coaching."]', '[]', 'I want to be direct and supportive at the same time: your language is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Professional language matters for credibility — we need to address this directly.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (53, 4, 'Meticulous records, punctual, conscientious.', '["Records are current and accurate","Never late","Paperwork always on time"]', '["Continue patterns"]', '["Share your systems with peers."]', '[]', 'Your practice in reliability reflects mastery-level work that should be named, preserved, and shared with colleagues. Your reliability makes the whole school run better.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (53, 3, 'Punctual and reliable with paperwork and assignments.', '["On time","Accurate records","Reliable follow-through"]', '["Maintain systems","Share what works with colleagues"]', '[]', '[]', 'Your reliability is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Your reliability is professional and consistent.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (53, 2, 'Occasionally skips assignments, is late, or misses paperwork deadlines.', '["Occasional missed deadlines","Some late arrivals","Records sometimes inaccurate"]', '["Use a calendar with reminders for all deadlines","Set up a weekly admin time block"]', '["Systems coaching."]', '[]', 'Your reliability shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A simple calendar-reminder system closes this gap.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (53, 1, 'Frequently skips assignments, is late, or misses deadlines.', '["Pattern of missed deadlines","Chronic tardiness","Record-keeping errors"]', '["Weekly check-in with principal on deadlines"]', '["Accountability coaching."]', '[]', 'I want to be direct and supportive at the same time: your reliability is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Reliability is a baseline — we will establish a system.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (54, 4, 'Always presents as a consummate professional with appropriate boundaries.', '["Professional demeanor in all interactions","Appropriate dress","Clear boundaries"]', '["Continue patterns","Mentor newer teachers"]', '["Model professionalism for induction."]', '[]', 'Your practice in professionalism reflects mastery-level work that should be named, preserved, and shared with colleagues. Your professionalism sets a tone for the whole building.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (54, 3, 'Demonstrates professional demeanor and maintains appropriate boundaries.', '["Generally professional","Appropriate boundaries"]', '["Maintain patterns"]', '[]', '[]', 'Your professionalism is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Your professionalism is solid — maintain it.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (54, 2, 'Occasional lapses in professional demeanor, dress, or boundaries.', '["Occasional issues","Some boundary confusion"]', '["Review district professionalism expectations","Seek mentor feedback on professional presentation"]', '["Professional-presentation coaching."]', '[]', 'Your professionalism shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A review of professional expectations will close this gap.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (54, 1, 'Frequent professionalism issues that impact the learning environment.', '["Regular boundary issues","Unprofessional dress or demeanor"]', '["Immediate conversation with principal"]', '["Formal professionalism plan."]', '[]', 'I want to be direct and supportive at the same time: your professionalism is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Professionalism is a baseline expectation — we will address this directly.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (55, 4, 'Invariably ethical, honest, forthright; impeccable judgment; respects confidentiality.', '["Ethical decision-making","Honest communication","Confidentiality respected"]', '["Continue patterns","Mentor colleagues on ethical decision-making"]', '["Model ethical judgment."]', '[]', 'Your practice in judgment reflects mastery-level work that should be named, preserved, and shared with colleagues. Your judgment is a pillar of trust in the school.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (55, 3, 'Ethical and forthright, uses good judgment, maintains confidentiality.', '["Ethical behavior","Good judgment","Confidentiality maintained"]', '["Maintain patterns"]', '[]', '[]', 'Your judgment is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Your ethical practice is solid.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (55, 2, 'Questionable judgment at times; occasionally less than honest; sometimes discloses student information.', '["Occasional questionable decisions","Some confidentiality concerns"]', '["Review FERPA and district ethics policies","Consult with principal on gray-area decisions"]', '["Ethics-and-FERPA coaching."]', '[]', 'Your judgment shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A FERPA/ethics refresher closes this gap.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (55, 1, 'Frequently unethical, dishonest, poor judgment, or discloses student information.', '["Repeated ethical concerns","FERPA violations"]', '["Immediate formal intervention"]', '["Formal ethics plan."]', '[]', 'I want to be direct and supportive at the same time: your judgment is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. This is a formal matter requiring immediate intervention.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (56, 4, 'Important member of teacher teams and committees, frequently volunteers for after-school activities.', '["Committee leadership","After-school involvement","Team contributions"]', '["Continue engagement"]', '["Invite into school leadership work."]', '[]', 'Your practice in above-and-beyond reflects mastery-level work that should be named, preserved, and shared with colleagues. Your contributions beyond the classroom build the school culture.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (56, 3, 'Shares responsibility for grade-level and schoolwide activities.', '["Team member","After-school involvement"]', '["Take on one leadership role"]', '[]', '[]', 'Your above-and-beyond is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Taking on a leadership role is the next step.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (56, 2, 'Will serve when asked but doesn''t initiate.', '["Reactive involvement","Minimal initiative"]', '["Volunteer for one committee or activity this semester"]', '["Engagement-invitation coaching."]', '[]', 'Your above-and-beyond shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Moving from reactive to proactive engagement is the move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (56, 1, 'Declines invitations to serve and attend activities.', '["Refuses committee work","No after-school engagement"]', '["Conversation with principal about school contribution expectations"]', '["Expectation-setting conversation."]', '[]', 'I want to be direct and supportive at the same time: your above-and-beyond is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. All staff contribute to the school beyond the classroom — we need to discuss expectations.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (57, 4, 'Frequently contributes valuable ideas and instills in others a desire to improve student results.', '["Thought leadership","Positive influence on colleagues","Drives improvement"]', '["Continue leadership","Take on formal leadership roles"]', '["Formal leadership pipeline."]', '[]', 'Your practice in leadership reflects mastery-level work that should be named, preserved, and shared with colleagues. Your leadership is building our school.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (57, 3, 'Positive team player, contributes ideas, expertise, and time.', '["Active contribution","Team support","Positive attitude"]', '["Take on one initiative leadership role"]', '[]', '[]', 'Your leadership is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Stepping into an initiative leadership role is the next growth move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (57, 2, 'Occasional suggestions but not consistent leadership.', '["Occasional ideas","Limited follow-through"]', '["Volunteer to lead one team initiative","Bring one idea per month to the team"]', '["Leadership-development coaching."]', '[]', 'Your leadership shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Consistency in contribution is the move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (57, 1, 'Rarely contributes ideas to improving the school.', '["No team contribution","No ideas offered"]', '["Commit to one idea per team meeting"]', '["Engagement-building coaching."]', '[]', 'I want to be direct and supportive at the same time: your leadership is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Being a contributing team member is an expectation — let''s build the habit.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (58, 4, 'Actively seeks feedback and uses it to improve.', '["Requests feedback regularly","Acts on feedback","Visible growth"]', '["Continue patterns","Mentor colleagues in feedback reception"]', '["Model feedback-seeking behavior."]', '[{"title":"The Impact Cycle","source":"Jim Knight (Corwin, 2017)","type":"book"}]', 'Your practice in openness reflects mastery-level work that should be named, preserved, and shared with colleagues. Your feedback-seeking mindset is exactly what our coaching culture needs.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (58, 3, 'Listens thoughtfully and responds constructively to suggestions.', '["Receives feedback well","Constructive response","Some action"]', '["Move from receiving to requesting feedback","Close the feedback loop with specific action"]', '["Feedback-request coaching."]', '[{"title":"The Impact Cycle","source":"Jim Knight (Corwin, 2017)","type":"book"}]', 'Your openness is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Requesting feedback proactively is the upgrade.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (58, 2, 'Somewhat defensive but does listen.', '["Initial defensiveness","Partial listening","Limited action on feedback"]', '["Practice receiving feedback with curiosity (\"Tell me more\")","Name one feedback item to act on weekly"]', '["Feedback-reception coaching."]', '[{"title":"The Impact Cycle","source":"Jim Knight (Corwin, 2017)","type":"book"}]', 'Your openness shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Moving from defense to curiosity is the work.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (58, 1, 'Very defensive; resistant to changing practice.', '["Strong defensiveness","Resistance to change","No growth from feedback"]', '["Work with coach to build feedback reception skills"]', '["Intensive feedback-reception coaching."]', '[{"title":"The Impact Cycle","source":"Jim Knight (Corwin, 2017)","type":"book"}]', 'I want to be direct and supportive at the same time: your openness is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Openness to feedback is foundational — we will work on this together.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (59, 4, 'Meets at least weekly with colleagues to plan, share teaching ideas, and analyze assessments.', '["Regular PLC participation","Data analysis with peers","Shared unit planning"]', '["Continue patterns","Lead PLC work"]', '["PLC facilitation training."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your practice in collaboration reflects mastery-level work that should be named, preserved, and shared with colleagues. Your collaborative practice is what Hattie calls "collective teacher efficacy" — the top effect size in his research.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (59, 3, 'Collaborates with colleagues to plan units, share ideas, look at student work.', '["Regular collaboration","Shared planning","Some student-work analysis"]', '["Move to weekly collaboration","Add interim-assessment analysis"]', '["Weekly-PLC coaching."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your collaboration is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. Weekly structured collaboration is the move.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (59, 2, 'Occasional collaboration but not systematic.', '["Some conversations","No shared planning","No data analysis together"]', '["Commit to weekly PLC participation","Bring one data question per week"]', '["PLC-participation coaching."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your collaboration shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. Weekly PLC engagement is the baseline.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (59, 1, 'Meets infrequently and conversations lack educational substance.', '["Avoids collaboration","Shallow conversations","No team participation"]', '["Required weekly PLC participation"]', '["PLC-facilitation support."]', '[{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'I want to be direct and supportive at the same time: your collaboration is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Collaborative practice is required — we will establish it.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (60, 4, 'Actively reaches out for new ideas and engages in action research.', '["Action research projects","Reading and implementing new research","Continuous learner"]', '["Continue learning","Share action research with team"]', '["Action-research support."]', '[{"title":"The Impact Cycle","source":"Jim Knight (Corwin, 2017)","type":"book"},{"title":"Visible Learning for Teachers","source":"John Hattie (Routledge, 2012)","type":"book"}]', 'Your practice in growth reflects mastery-level work that should be named, preserved, and shared with colleagues. Your professional growth mindset models lifelong learning for students.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (60, 3, 'Seeks effective teaching ideas from colleagues, workshops, and other sources.', '["PD participation","Tries new strategies","Learning from colleagues"]', '["Build a formal learning plan with 3 growth goals","Read one professional book per semester"]', '["Learning-plan coaching."]', '[{"title":"The Impact Cycle","source":"Jim Knight (Corwin, 2017)","type":"book"}]', 'Your growth is solid and professionally sound — the kind of steady, student-centered practice the Marshall rubric describes as Effective. A formal learning plan with measurable goals is the move toward Highly Effective.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (60, 2, 'Can occasionally be persuaded to try new practices.', '["Reluctant to try new things","Limited professional reading","Low PD engagement"]', '["Commit to one new practice per month","Attend one PD per semester outside required"]', '["Growth-habit coaching."]', '[{"title":"The Impact Cycle","source":"Jim Knight (Corwin, 2017)","type":"book"}]', 'Your growth shows the right instincts, but the evidence from the observation tells me we have room to lift this area to Effective with a targeted next step. A monthly "new practice to try" habit builds growth mindset.');
INSERT OR REPLACE INTO pedagogy_library (indicator_id, level, interpretation, evidence_signals, teacher_next_moves, coaching_considerations, resources, feedback_starter) VALUES (60, 1, 'Not open to new ideas for improving teaching.', '["Resistance to change","No PD engagement","Static practice"]', '["Build a formal growth plan with principal"]', '["Intensive growth-mindset coaching."]', '[{"title":"The Impact Cycle","source":"Jim Knight (Corwin, 2017)","type":"book"}]', 'I want to be direct and supportive at the same time: your growth is not yet meeting the standard our students deserve, and this needs to be an immediate focus area with coaching support. Growth is required in our profession — we need to build a formal plan.');
